import{_ as e,o as i,c as l,ac as t}from"./chunks/framework.DnBnwVZk.js";const v=JSON.parse('{"title":"Java静态变量、inline初始化的实例变量，显示与隐式调用构造器的执行顺序","description":"","frontmatter":{"date":"2019-11-22T00:00:00.000Z","categories":["Java进阶"],"tags":[null],"publish":true},"headers":[],"relativePath":"views/java/knowledge/JavaClassInitSequence.md","filePath":"views/java/knowledge/JavaClassInitSequence.md","lastUpdated":1775714960000}'),n={name:"views/java/knowledge/JavaClassInitSequence.md"};function o(s,a,r,d,c,_){return i(),l("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1574380800000"},[...a[0]||(a[0]=[t('<h1 id="java静态变量、inline初始化的实例变量-显示与隐式调用构造器的执行顺序" tabindex="-1">Java静态变量、inline初始化的实例变量，显示与隐式调用构造器的执行顺序 <a class="header-anchor" href="#java静态变量、inline初始化的实例变量-显示与隐式调用构造器的执行顺序" aria-label="Permalink to &quot;Java静态变量、inline初始化的实例变量，显示与隐式调用构造器的执行顺序&quot;">​</a></h1><ol><li>所有依赖路径的类（包括父类与子类）加载，类变量初始化和静态代码块执行，注意一个类只会被加载一次，顺序如下： <ol><li>加载父类，其中类加载过程中类变量和静态变量的顺序如下： <ol><li>静态变量</li><li>静态代码块</li></ol></li><li>加载子类，顺序同上</li></ol></li><li>实例变量初始化与构造器调用，先执行父类，再执行子类，注意每次新建类的实例时都会完整执行一遍 <ol><li>父类实例变量初始化与构造器 <ol><li>父类inline实例变量初始化过程</li><li>父类构造器，如果子类被调用到的构造器中通过super()或者super(param)显式调用了父构造器，则执行被调用的构造器，否则执行空构造器</li></ol></li><li>子类实例变量初始化与构造器 <ol><li>子类inline实例变量初始化过程</li><li>子类构造器调用，被调用哪个就执行哪个，除非显式调用this()，否则不会调用子类的空构造器</li></ol></li></ol></li></ol><p>因此，反直觉的是，反而是调用到的子类的构造方法，最后被执行</p>',3)])])}const u=e(n,[["render",o]]);export{v as __pageData,u as default};
